const html = $json.data;

const rows = [...html.matchAll(/<tr[\s\S]*?<\/tr>/gi)];

let results = [];

rows.forEach(rowMatch => {
  const row = rowMatch[0];

  // Extract PDF link
  const linkMatch = row.match(/href="(.*?\.pdf)"/i);

  if (linkMatch) {
    let link = linkMatch[1];

    if (!link.startsWith('http')) {
      link = 'https://www.rbi.org.in' + link;
    }

    // Extract title → remove all tags, keep text
    let cleanText = row
      .replace(/<[^>]*>/g, ' ')   // remove HTML tags
      .replace(/\s+/g, ' ')       // normalize spaces
      .trim();

    // Remove date + file size noise (optional cleanup)
    cleanText = cleanText
      .replace(/Apr \d{2}, \d{4}/i, '')
      .replace(/\d+\s*kb/i, '')
      .trim();

    results.push({
      title: cleanText,
      url: link
    });
  }
});

// dedup
const unique = Array.from(new Map(results.map(item => [item.url, item])).values());

return unique.slice(0, 10).map(item => ({ json: item }));

return items.map(item => {
  return {
    json: {
      title: item.json.title,
      url: item.json.link,
      source: "RBI_RSS",
      published_at: item.json.pubDate,

      // optional: extract short clean text
      summary: item.json.content
        ?.replace(/<[^>]*>/g, ' ')   // remove HTML
        .replace(/\s+/g, ' ')
        .trim()
        .slice(0, 300) // keep short
    }
  };
});

// FUZZY DEDUP BY TITLE (handles messy real-world data)

function similarity(a, b) {
  const longer = a.length > b.length ? a : b;
  const shorter = a.length > b.length ? b : a;

  const longerLength = longer.length;
  if (longerLength === 0) return 1.0;

  return (longerLength - editDistance(longer, shorter)) / longerLength;
}

function editDistance(a, b) {
  const matrix = [];

  for (let i = 0; i <= b.length; i++) matrix[i] = [i];
  for (let j = 0; j <= a.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= b.length; i++) {
    for (let j = 1; j <= a.length; j++) {
      if (b.charAt(i - 1) === a.charAt(j - 1)) {
        matrix[i][j] = matrix[i - 1][j - 1];
      } else {
        matrix[i][j] = Math.min(
          matrix[i - 1][j - 1] + 1,
          matrix[i][j - 1] + 1,
          matrix[i - 1][j] + 1
        );
      }
    }
  }

  return matrix[b.length][a.length];
}

const results = [];

for (const item of $input.all()) {
  const data = item.json;

  const rawTitle = (data.title || "").trim();
  const link = (data.link || data.url || data.guid || "").trim();

  if (!rawTitle || !link) continue;

  // --- CLEAN TITLE ---
  const cleanedTitle = rawTitle
    .replace(/<[^>]*>/g, "")
    .replace(/style=.*?["']/g, "")
    .replace(/src=.*?["']/g, "")
    .replace(/&[^;]+;/g, " ")
    .replace(/[^a-zA-Z0-9 ]/g, " ")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();

  let isDuplicate = false;

  for (const existing of results) {
    const score = similarity(cleanedTitle, existing.json._normalizedTitle);

    if (score > 0.85) {
      isDuplicate = true;

      // Prefer RSS
      if (data.source === "RBI_RSS" && existing.json.source !== "RBI_RSS") {
        existing.json = {
          ...existing.json,
          ...item.json,
          title: cleanedTitle
        };
      }

      break;
    }
  }

  if (!isDuplicate) {
    results.push({
      json: {
        ...item.json,
        title: cleanedTitle,
        _normalizedTitle: cleanedTitle, // internal use
        created_at: new Date().toISOString()
      }
    });
  }
}

// remove helper field
return results.map(item => {
  delete item.json._normalizedTitle;
  return item;
});

const html = $json.data;

// Extract all anchor tags
const links = [...html.matchAll(/<a[^>]+href="([^"]+)"[^>]*>(.*?)<\/a>/gi)];

let results = [];

links.forEach(match => {
  let url = match[1];
  let title = match[2];

  // Clean title
  title = title
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // Skip invalid links
  if (!url || url.includes('#') || url.includes('javascript')) return;

  // Normalize URL
  if (!url.startsWith('http')) {
    url = 'https://www.sebi.gov.in' + url;
  }

  // Keep only relevant circulars
  if (
    url.includes('circular') ||
    url.includes('legal') ||
    url.endsWith('.pdf')
  ) {
    // Avoid weak titles
    if (title.length < 25) return;

    results.push({
      title,
      url,
      source: "SEBI"
    });
  }
});

// Deduplicate
const unique = Array.from(
  new Map(results.map(item => [item.url, item])).values()
);

// Limit
return unique.slice(0, 10).map(item => ({ json: item }));

return items.map(item => {
  const content = item.json.content || item.json.contentSnippet || "";

  return {
    json: {
      title: item.json.title || "",
      url: item.json.link || item.json.guid || "",
      source: "SEBI_RSS", // change to "RBI_RSS" for RBI flow
      published_at: item.json.pubDate || "",

      summary: content
        .replace(/<[^>]*>/g, ' ')   // remove HTML
        .replace(/\s+/g, ' ')       // normalize spaces
        .trim()
        .slice(0, 300)
    }
  };
});
